/**
 * Database connection configuration for postgres engine (DB).
 *
 * When DB_DATABASE_URL is set (e.g. in Docker), the URL is
 * used directly.  Otherwise individual host/port/username/password env vars
 * are required (local development).
 *
 * Auto-generated by datrix-codegen-typescript. Do not edit manually.
 */
import { TypeOrmModuleOptions } from '@nestjs/typeorm';
import { ConfigService } from '@nestjs/config';

export function getDatabaseConfig(
  configService: ConfigService,
): TypeOrmModuleOptions {
  const databaseUrl = process.env['DB_DATABASE_URL'];
  const baseOptions: Partial<TypeOrmModuleOptions> = {
    type: 'postgres',
    entities: [__dirname + '/../entities/**/*.entity{.ts,.js}'],
    synchronize: configService.get<boolean>('DATABASE_SYNC', false),
    logging: configService.get<boolean>('DATABASE_LOGGING', false),
    extra: {
      max: 20,
    },
  };

  if (databaseUrl) {
    return {
      ...baseOptions,
      url: databaseUrl,
    } as TypeOrmModuleOptions;
  }

  return {
    ...baseOptions,
    host: 'localhost',
    port: 5432,
    username: (() => {
      const k = 'DB_DB_USER';
      if (!process.env[k]) {
        throw new Error(`${k} environment variable is required`);
      }
      return process.env[k] as string;
    })(),
    password: (() => {
      const k = 'DB_DB_PASSWORD';
      if (!process.env[k]) {
        throw new Error(`${k} environment variable is required`);
      }
      return process.env[k] as string;
    })(),
    database: 'ecommerce_payments',
  } as TypeOrmModuleOptions;
}
